easy.solution:
// TypeScript implementation for Void and Never
interface VoidandNeverPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processVoidandNever(item: VoidandNeverPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processVoidandNever({ id: 1, title: 'Void and Never', status: 'active' }));

